package com.example.sso.controller;

import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Set;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;

import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.PostMapping;

@Controller
public class LogoutController {

    private static final Set<String> ALLOWED_HOSTS = Set.of(
        "app.example.com",
        "portal.example.com",
        "localhost"
    );

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        String next = request.getParameter("next");
        String safeRedirect = validateRedirect(next);

        if (safeRedirect == null) {
            response.sendError(HttpStatus.BAD_REQUEST.value(), "Invalid redirect target");
            return;
        }

        response.sendRedirect(safeRedirect);
    }

    private String validateRedirect(String next) {
        if (next == null || next.isBlank()) {
            return null;
        }

        try {
            URI uri = new URI(next);

            if (!uri.isAbsolute()) {
                if (next.startsWith("/") && !next.startsWith("//") && !next.contains("\r") && !next.contains("\n")) {
                    return next;
                }
                return null;
            }

            String scheme = uri.getScheme();
            String host = uri.getHost();

            if (scheme == null || host == null) {
                return null;
            }

            if (!("https".equalsIgnoreCase(scheme) || "http".equalsIgnoreCase(scheme))) {
                return null;
            }

            if (!ALLOWED_HOSTS.contains(host.toLowerCase())) {
                return null;
            }

            if (next.contains("\r") || next.contains("\n")) {
                return null;
            }

            return next;
        } catch (URISyntaxException e) {
            return null;
        }
    }
}